// get user name
function getUserName(user: string): string {
    return user;
}

// increment counter value
function incrementCounterValue(counter: number, value: number): number {
    return counter + value;
}

// validate input data
function validateInputData(input: string, data: unknown[]): boolean {
    return input.length > 0 && data.length > 0;
}

// calculate total price
function calculateTotalPrice(total: number, price: number): number {
    return total + price;
}
